export const generateServiceSchema = (serviceName: string, description: string, url: string) => ({
  "@context": "https://schema.org",
  "@type": "Service",
  name: serviceName,
  description: description,
  url: url,
  provider: {
    "@type": "Organization",
    name: "WIZ Management Solutions",
    url: "https://wizms.net",
  },
  areaServed: {
    "@type": "Country",
    name: "AE",
  },
});

export const generateBreadcrumbSchema = (breadcrumbs: Array<{ name: string; url: string }>) => ({
  "@context": "https://schema.org",
  "@type": "BreadcrumbList",
  itemListElement: breadcrumbs.map((item, index) => ({
    "@type": "ListItem",
    position: index + 1,
    name: item.name,
    item: item.url,
  })),
});

export const generateFAQSchema = (faqs: Array<{ question: string; answer: string }>) => ({
  "@context": "https://schema.org",
  "@type": "FAQPage",
  mainEntity: faqs.map((faq) => ({
    "@type": "Question",
    name: faq.question,
    acceptedAnswer: {
      "@type": "Answer",
      text: faq.answer,
    },
  })),
});

export const generateArticleSchema = (title: string, description: string, author: string, publishDate: string, image?: string) => ({
  "@context": "https://schema.org",
  "@type": "Article",
  headline: title,
  description: description,
  image: image || "https://wizms.net/logo.webp",
  author: {
    "@type": "Organization",
    name: author,
  },
  datePublished: publishDate,
  dateModified: publishDate,
});

